// --- Utility: Allowed keywords check (used during deeper validation if needed) ---
func isAllowedIdentifier(word string) bool {
	if allowedProtoKeywords[word] {
		return true
	}
	if allowedProtoTypes[word] {
		return true
	}
	// Allow user-defined identifiers that are purely alphanumeric with underscores
	identRegex := regexp.MustCompile(`^[a-zA-Z_][a-zA-Z0-9_.]*$`)
	return identRegex.MatchString(word)
}